# fix-hero-bg-responsive.ps1
# Fixes Hero background slider responsiveness (desktop/mobile picture sources,
# tuned object-position) and expands hero_bg_images into rich slide objects
# (desktopUrl/mobileUrl/title/subtitle/description/buttonText/buttonLink/order/active)
# ready for the future Admin CMS.
$ErrorActionPreference = 'Stop'
Write-Host "Applying Hero background responsive fix..." -ForegroundColor Cyan

Write-Host "Writing src\components\public\HeroSection.tsx"
$dir = Split-Path -Parent "src\components\public\HeroSection.tsx"
if ($dir -and !(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
$b64HeroSection = @"

"@
[System.IO.File]::WriteAllBytes("src\components\public\HeroSection.tsx", [System.Convert]::FromBase64String($b64HeroSection))

Write-Host "Writing src\app\[locale]\page.tsx"
$dir = Split-Path -Parent "src\app\[locale]\page.tsx"
if ($dir -and !(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
$b64LocalePage = @"

"@
[System.IO.File]::WriteAllBytes("src\app\[locale]\page.tsx", [System.Convert]::FromBase64String($b64LocalePage))

Write-Host "Writing src\app\admin\(protected)\profile\page.tsx"
$dir = Split-Path -Parent "src\app\admin\(protected)\profile\page.tsx"
if ($dir -and !(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
$b64ProfileAdminPage = @"

"@
[System.IO.File]::WriteAllBytes("src\app\admin\(protected)\profile\page.tsx", [System.Convert]::FromBase64String($b64ProfileAdminPage))

Write-Host "Writing src\app\admin\(protected)\profile\ProfileForm.tsx"
$dir = Split-Path -Parent "src\app\admin\(protected)\profile\ProfileForm.tsx"
if ($dir -and !(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
$b64ProfileForm = @"

"@
[System.IO.File]::WriteAllBytes("src\app\admin\(protected)\profile\ProfileForm.tsx", [System.Convert]::FromBase64String($b64ProfileForm))

Write-Host "Done. 4 files updated." -ForegroundColor Green